const iconsDirPath = './src/assets/icons'
const iconsObjectFileDirPath = './src/datas/icons'

const getDirectories = (srcpath) => {
  return fs.readdirSync(srcpath)
    .map(file => path.join(srcpath, file))
    .filter(path => fs.statSync(path).isDirectory());
}

const createObj = () => {
  fs.rmSync(iconsObjectFileDirPath, { recursive: true })
  fs.mkdirSync(iconsObjectFileDirPath);

  const directories = getDirectories(iconsDirPath)
  let fileContent = 'export const ICONS = {'
  directories.forEach((dir, index) => {
    const dirName = path.basename(dir, '')
    **const spriter = new SVGSpriter({
      log: 'info',
      dest: './public/sprite/' + dirName,
      mode: {
        defs: {
          sprite: "svg/sprite.css.svg",
          example: true
        }
      }
    })**
    if (index === 0) {
      fileContent += '\n  '
    }
    fileContent += dirName + ': ['
    const files = fs.readdirSync(dir)
    let count = 0
    files.forEach((file) => {
      if (file.match(/([a-z0-6-]*).svg/)) {
        filePath = iconsDirPath + '/' + dirName + '/' + file
        **spriter.add(filePath, null, fs.readFileSync(filePath, 'utf-8'))**

        const name = path.basename(file, '.svg')
        const sp = name.split('-').filter(item => item.match(/^[0-9]{1}[a-z]{1}/))
        if (count > 0) {
          fileContent += ", "
        }
        fileContent += "{ name: '" + name + "', filters: "+ JSON.stringify(sp).replaceAll('"', '\'').replaceAll(',', ', ') + " }"
        count++
      }
    })
    fileContent += ']'
    if (index < directories.length - 1) {
      fileContent += ',\n  '
    } else {
      fileContent += '\n'
    }

    **spriter.compile((error, result) => {
      for (const mode in result) {
          for (const resource in result[mode]) {
              fs.mkdirSync(path.dirname(result[mode][resource].path), { recursive: true });
              fs.writeFileSync(result[mode][resource].path, result[mode][resource].contents);
          }
      }
    })**
  })
  fileContent += '}\n'
  fileContent += 'export default ICONS\n'
  fs.appendFileSync(iconsObjectFileDirPath + '/index.js', fileContent)
}

createObj()

```
The script generate one sprite by existing folder.
The sprite's files are well created but when the icons aren't displayed in my VueJS app.

When I use a command like `svg-sprite -d --dx --dest=./public/sprite/documents ./src/assets/icons/documents/*.svg`, the sprite file is created and the icon are well displayed.

